static inline mode_t
mixtar_acl_to_mode(struct mixtar_acl_mode *acl, mode_t old_mode)
{
	mode_t mode = old_mode & ~(mode_t)0777;
	int have_user = 0;
	int have_group = 0;
	int have_other = 0;

	for (int i = 0; i < acl->count; i++) {
		if (acl->entries[i].tag == ACL_USER_OBJ) {
			mode |= mixtar_acl_mode_from_perm(acl->entries[i].perm,
			    S_IRUSR, S_IWUSR, S_IXUSR);
			have_user = 1;
		} else if (acl->entries[i].tag == ACL_GROUP_OBJ) {
			mode |= mixtar_acl_mode_from_perm(acl->entries[i].perm,
			    S_IRGRP, S_IWGRP, S_IXGRP);
			have_group = 1;
		} else if (acl->entries[i].tag == ACL_OTHER) {
			mode |= mixtar_acl_mode_from_perm(acl->entries[i].perm,
			    S_IROTH, S_IWOTH, S_IXOTH);
			have_other = 1;
		}
	}
	if (!have_user)
		mode |= old_mode & 0700;
	if (!have_group)
		mode |= old_mode & 0070;
	if (!have_other)
		mode |= old_mode & 0007;
	return mode;
}

